function solve(points) {
    const MOD = 10**9 + 7;
    const freq = new Map();
    for (const [x, y] of points) {
        if (!freq.has(y)) {
            freq.set(y, 0);
        }
        freq.set(y, freq.get(y) + 1);
    }
    const counts = Array.from(freq.values());
    const inv_2 = 500000004; // Modular inverse of 2 under MOD
    let total_x = 0;
    let sum_x2 = 0;
    for (const cnt of counts) {
        if (cnt < 2) continue;
        const temp = (cnt * (cnt - 1)) % MOD;
        const x_i = (temp * inv_2) % MOD;
        total_x = (total_x + x_i) % MOD;
        sum_x2 = (sum_x2 + x_i * x_i) % MOD;
    }
    const total_x_squared = (total_x * total_x) % MOD;
    const numerator = (total_x_squared - sum_x2 + MOD) % MOD;
    const ans = (numerator * inv_2) % MOD;
    return ans;
}

